module div_16bit(
    input [15:0] A,
    input [7:0] B,
    output reg [15:0] result,
    output [15:0] odd
);

always @(*) begin
    if (A[15:8] >= B) begin
        result = {8'b0, 1'b1, A[7:0]};
    end else begin
        result = {8'b0, 1'b0, A[7:0]};
    end
end

assign odd = A - (result[15:8] * B);

endmodule
